CVE-2026-32177.script:
# Détection fallback (OVAL non disponible) : CVE-2026-32177
# Vérifie la présence des correctifs via Windows Update
$kbCorrecifs = @("KB5093446", "KB5093447", "KB5093448", "KB5087065", "KB5087067", "KB5087069", "KB5087066", "KB5087068", "KB5087064", "KB5087061", "KB5087062", "KB5087063", "KB5087059", "KB5087053", "KB5087058", "KB5087051", "KB5087055", "KB5087054", "KB5087048", "KB5087049")
$Session  = New-Object -ComObject Microsoft.Update.Session
$Searcher = $Session.CreateUpdateSearcher()
$Updates  = $Searcher.Search("IsInstalled=1").Updates
$installes = $Updates | ForEach-Object { $_.KBArticleIDs } | ForEach-Object { "KB$_" }
$manquants = $kbCorrecifs | Where-Object { $installes -notcontains $_ }
if ($manquants.Count -eq 0) {
